package com.whoismacy.android.incidentincidence.routes.extraroutes

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.rememberNavController

@Composable
fun ExtraHost() {
    val extraNavHost = rememberNavController()
    NavHost(
        navController = extraNavHost,
        startDestination = null,
    ) {
    }
}

package com.whoismacy.android.incidentincidence.routes.extraroutes

import androidx.compose.runtime.Composable
import androidx.compose.runtime.CompositionLocalProvider
import androidx.compose.runtime.staticCompositionLocalOf
import androidx.hilt.navigation.compose.hiltViewModel
import androidx.lifecycle.compose.collectAsStateWithLifecycle
import androidx.navigation.NavController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.rememberNavController
import com.whoismacy.android.incidentincidence.viewmodel.IncidentViewModel
import kotlinx.serialization.Serializable

@Serializable
data object CreateIncidentRoute

@Serializable
data object CaptureImageRoute

@Serializable
data class EditRoute(val id: Int)

val LocalExtraNavController =
    staticCompositionLocalOf<NavController> {
        error("No Extra NavController provided")
    }

@Composable
fun ExtraHost(
    onReturnToMain: () -> Unit,
    viewModel: IncidentViewModel = hiltViewModel(),
) {
    val displayData by viewModel
        .displayIncidences
        .collectAsStateWithLifecycle()

    val extraNavController = rememberNavController()

    CompositionLocalProvider(LocalExtraNavController provides extraNavController) {
        NavHost(
            navController = extraNavController,
            startDestination = CreateIncidentRoute,
        ) {
            createIncidentDestination(onNavigateBack = onReturnToMain)
            captureImageDestination()
            editDestination(incidents = displayData)
        }
    }
}

package com.whoismacy.android.incidentincidence.view

