@Composable
fun SearchBar(
    state: String,
    viewModel: IncidentViewModel = hiltViewModel(),
) {
    var showSortFilterModal by remember { mutableStateOf(false) }
    val changeSortFilterState: (Boolean) -> Unit = { showSortFilterModal = it }
    val showFilter =
        viewModel
            .displayFilterState
            .collectAsStateWithLifecycle()
            .value.filtersEnabled
    val isLoading = viewModel.isLoading.collectAsStateWithLifecycle().value

    Box(
        modifier = Modifier.fillMaxWidth().padding(top = 48.dp, bottom = 32.dp),
        contentAlignment = Alignment.Center,
    ) {
        TextField(
            value = state,
            onValueChange = { viewModel.updateSearchQuery(it) },
            singleLine = true,
            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Text),
            placeholder = {
                Text("Search")
            },
            leadingIcon = {
                Icon(
                    painter = painterResource(R.drawable.baseline_search_24),
                    contentDescription = null,
                )
            },
            shape = MaterialTheme.shapes.extraLarge,
            colors =
                TextFieldDefaults.colors(
                    focusedIndicatorColor = Color.Transparent,
                    unfocusedIndicatorColor = Color.Transparent,
                    errorIndicatorColor = Color.Transparent,
                ),
            modifier = Modifier.shimmer(16.dp, isLoading),
            trailingIcon = {
                if (!showFilter) {
                    IconButton(
                        onClick = {
                            changeSortFilterState(true)
                        },
                        modifier = Modifier.shimmer(8.dp, isLoading),
                    ) {
                        Icon(
                            painter = painterResource(R.drawable.sharp_filter_alt_24),
                            contentDescription = "Filter Icon",
                            tint = MaterialTheme.colorScheme.onSurfaceVariant,
                        )
                    }
                } else {
                    TextButton(onClick = {
                        viewModel.toggleFilters()
                    }) {
                        Text(
                            "Clear Filters",
                            style = MaterialTheme.typography.labelSmall,
                            fontWeight = FontWeight.ExtraBold,
                        )
                    }
                }
            },
        )
    }

    if (showSortFilterModal) {
        SortFilterComponent({ changeSortFilterState(false) }, viewModel = viewModel)
    }
}

